import React, { useState, useEffect } from "react";
import Logo from "./Logo";
import LoginForm from "./LoginForm";
import RegisterForm from "./RegisterForm";
import HomePage from "./HomePage";
import FriendList from "./FriendList";              
import NotificationList from "./NotificationList";  
import Header from "./components/Header";
import Sidebar from "./components/Sidebar";

export default function App() {
  const [screen, setScreen] = useState("logo");
  const [input1, setInput1] = useState("");

  // Tự động chuyển từ logo sang login
  useEffect(() => {
    if (screen === "logo") {
      const timer = setTimeout(() => setScreen("login"), 2000);
      return () => clearTimeout(timer);
    }
  }, [screen]);

  const handleLoginSuccess = () => setScreen("home");

  return (
    <div>
      {screen === "logo" && <Logo />}

      {screen === "login" && (
        <LoginForm
          goToRegister={() => setScreen("register")}
          onLoginSuccess={handleLoginSuccess}
        />
      )}

      {screen === "register" && (
        <RegisterForm goToLogin={() => setScreen("login")} />
      )}

      {/* Các trang chính */}
      {["home", "friends", "notifications"].includes(screen) && (
        <>
          <Header input1={input1} onChangeInput1={setInput1} />
          <Sidebar onNavigate={setScreen} />

          <div className="pt-[140px] pl-[100px] pr-6">
            {screen === "home" && <HomePage />}
            {screen === "friends" && <FriendList />}
            {screen === "notifications" && <NotificationList />}
          </div>
        </>
      )}
    </div>
  );
}
